class House {
  constructor(color) {
    this.color = color; // Attribute
  }
  describe() {
    return `A ${this.color} house.`; // Method
  }
}
const myHouse = new House('red');
console.log(myHouse.describe());

class House:
    def __init__(self, color):
        self.color = color  # Attribute
    def describe(self):
        return f'A {self.color} house.'  # Method

my_house = House('red')
print(my_house.describe())

class House {
    private String color; // Attribute
    public House(String color) {
        this.color = color;
    }
    public String describe() {
        return "A " + this.color + " house.";
    }
}
public class Main {
    public static void main(String[] args) {
        House house = new House("red");
        System.out.println(house.describe());
    }
}

