    def render(self):
        return 'drawing shape...'
class Circle(Shape):
    def render(self):
        return 'drawing circle...'  # Overriding

shapes = [Shape(), Circle()]
for s in shapes:
    print(s.render())

class Shape {
    public void render() { System.out.println("drawing shape..."); }
}
class Circle extends Shape {
    @Override
    public void render() { System.out.println("drawing circle..."); }
}
public class Main {
    public static void main(String[] args) {
        Shape[] shapes = { new Shape(), new Circle() };
        for (Shape s : shapes) {
            s.render(); // Executes Circle version for Circle object!
        }
    }
}

