class CoffeeMachine {
    private String heatWater() { return "heating..."; }
    private String brew() { return "brewing..."; }
    public String makeCoffee() {
        return heatWater() + " and " + brew() + " done!";
    }
}
public class Main {
    public static void main(String[] args) {
        CoffeeMachine machine = new CoffeeMachine();
        System.out.println(machine.makeCoffee());
    }
}

// JS does not have interfaces; we mock contracts using errors
class DbConnection {
  connect() {
    throw new Error('Must implement connect()');
  }
}
class MongoDb extends DbConnection {
  connect() { return 'Mongo connected!'; }
}

from abc import ABC, abstractmethod

class DbConnection(ABC):
    @abstractmethod
    def connect(self):
        pass

class MongoDb(DbConnection):
    def connect(self):
        return 'Mongo connected!'

interface DbConnection {
    void connect(); // abstract contract signature
}
class MongoDb implements DbConnection {
    public void connect() {
        System.out.println("Mongo connected!");
    }
}

